        if (isBinary) continue;
        // Count newlines + 1 for trailing line without newline. Matches wc -l
        // semantics but handles paths with spaces (which wc -l invoked via
        // execFile does NOT) and binary detection (which utf-8 readFileSync
        // does NOT — it would throw on first invalid byte sequence).
        const content = buf.toString('utf-8');
